class CustomURLSessionDelegate: NSObject, URLSessionDelegate {
    func urlSession(_ session: URLSession, didReceive challenge: URLAuthenticationChallenge, completionHandler: @escaping (URLSession.AuthChallengeDisposition, URLCredential?) -> Void) {
        
        guard let serverTrust = challenge.protectionSpace.serverTrust else {
            completionHandler(.performDefaultHandling, nil)
            return
        }
        
        let host = challenge.protectionSpace.host
        
        if host.hasPrefix("192.168.") || host.hasPrefix("10.") || host.hasPrefix("172.") || host == "localhost" {
            let credential = URLCredential(trust: serverTrust)
            completionHandler(.useCredential, credential)
        } else if host.contains("api.example.com") {
            completionHandler(.performDefaultHandling, nil)
        } else {
            completionHandler(.performDefaultHandling, nil)
        }
    }
}

class CloudAPIClient {
    private let baseURL = "https://api.example.com"
    private let httpClient = HTTPClient.shared
    
    func getDevices(completion: @escaping (Result<[Device], HTTPClient.HTTPError>) -> Void) {
        let url = "\(baseURL)/devices"
        httpClient.request(url: url, method: .get, completion: completion)
    }
    
    func getDeviceStatus(deviceId: String, completion: @escaping (Result<DeviceStatus, HTTPClient.HTTPError>) -> Void) {
        let url = "\(baseURL)/devices/\(deviceId)/status"
        httpClient.request(url: url, method: .get, completion: completion)
    }
    
    func updateDevice(deviceId: String, data: [String: Any], completion: @escaping (Result<Device, HTTPClient.HTTPError>) -> Void) {
        let url = "\(baseURL)/devices/\(deviceId)"
        
        guard let jsonData = try? JSONSerialization.data(withJSONObject: data) else {
            completion(.failure(.decodingError))
            return
        }
        
        httpClient.request(url: url, method: .put, body: jsonData, completion: completion)
    }
}

class IoTDeviceClient {
    private let httpClient = HTTPClient.shared
    
    func discoverDevice(ipAddress: String, completion: @escaping (Result<IoTDeviceInfo, HTTPClient.HTTPError>) -> Void) {
        let url = "http://\(ipAddress)/info"
        httpClient.request(url: url, method: .get, completion: completion)
    }
    
    func sendCommand(ipAddress: String, command: String, parameters: [String: Any]? = nil, completion: @escaping (Result<CommandResponse, HTTPClient.HTTPError>) -> Void) {
        let url = "http://\(ipAddress)/command"
        
        var payload: [String: Any] = ["command": command]
        if let parameters = parameters {
            payload["parameters"] = parameters
        }
        
        guard let jsonData = try? JSONSerialization.data(withJSONObject: payload) else {
            completion(.failure(.decodingError))
            return
        }
        
        httpClient.request(url: url, method: .post, body: jsonData, completion: completion)
    }
    
    func getDeviceState(ipAddress: String, completion: @escaping (Result<IoTDeviceState, HTTPClient.HTTPError>) -> Void) {
        let url = "http://\(ipAddress)/state"
        httpClient.request(url: url, method: .get, completion: completion)
    }
    
    func updateDeviceState(ipAddress: String, state: [String: Any], completion: @escaping (Result<IoTDeviceState, HTTPClient.HTTPError>) -> Void) {
        let url = "http://\(ipAddress)/state"
        
        guard let jsonData = try? JSONSerialization.data(withJSONObject: state) else {
            completion(.failure(.decodingError))
            return
        }
        
        httpClient.request(url: url, method: .post, body: jsonData, completion: completion)
    }
}

